import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Typography,
  Grid,
  Paper,
  Card,
  CardContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Button,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  IconButton,
  Alert,
  Chip,
  List,
  ListItem,
  ListItemText,
  ListItemIcon,
  Divider,
  Tab,
  Tabs,
} from '@mui/material';
import {
  Event as EventIcon,
  People as PeopleIcon,
  LocalHospital as HospitalIcon,
  AccessTime as TimeIcon,
  Description as DescriptionIcon,
  Close as CloseIcon,
  CheckCircle as CheckCircleIcon,
  Cancel as CancelIcon,
  LocalPharmacy as PharmacyIcon,
  Warning as WarningIcon,
  Person as PersonIcon,
  Add as AddIcon,
  Today as TodayIcon,
  Schedule as ScheduleIcon,
  Star as StarIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
} from '@mui/icons-material';
import { useAuth } from '../../context/AuthContext';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { format } from 'date-fns';

const Dashboard = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState({
    totalAppointments: 0,
    todayAppointments: 0,
    totalPatients: 0,
    completedAppointments: 0,
    averageRating: 0,
  });
  const [todayAppointments, setTodayAppointments] = useState([]);
  const [recentPatients, setRecentPatients] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [openPrescriptionDialog, setOpenPrescriptionDialog] = useState(false);
  const [selectedAppointment, setSelectedAppointment] = useState(null);
  const [prescriptionForm, setPrescriptionForm] = useState({
    diagnosis: '',
    medications: [{ name: '', dosage: '', frequency: '', duration: '' }],
    instructions: '',
    sideEffects: [],
  });
  const [openDialog, setOpenDialog] = useState(false);
  const [prescriptionNote, setPrescriptionNote] = useState('');
  const [activeTab, setActiveTab] = useState(0);

  useEffect(() => {
    fetchDashboardData();
    fetchAppointments();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const [statsRes, appointmentsRes, patientsRes] = await Promise.all([
        axios.get('http://localhost:5000/api/doctor/stats', {
          headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
        }),
        axios.get('http://localhost:5000/api/doctor/today-appointments', {
          headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
        }),
        axios.get('http://localhost:5000/api/doctor/recent-patients', {
          headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
        }),
      ]);

      setStats(statsRes.data);
      setTodayAppointments(appointmentsRes.data);
      setRecentPatients(patientsRes.data);
    } catch (err) {
      setError('Failed to fetch dashboard data');
    } finally {
      setLoading(false);
    }
  };

  const fetchAppointments = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/doctors/appointments', {
        headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
      });
      setTodayAppointments(response.data);
    } catch (error) {
      console.error('Error fetching appointments:', error);
    }
  };

  const handleOpenPrescriptionDialog = (appointment) => {
    setSelectedAppointment(appointment);
    setPrescriptionForm({
      diagnosis: '',
      medications: [{ name: '', dosage: '', frequency: '', duration: '' }],
      instructions: '',
      sideEffects: [],
    });
    setOpenPrescriptionDialog(true);
  };

  const handleClosePrescriptionDialog = () => {
    setOpenPrescriptionDialog(false);
    setSelectedAppointment(null);
    setPrescriptionForm({
      diagnosis: '',
      medications: [{ name: '', dosage: '', frequency: '', duration: '' }],
      instructions: '',
      sideEffects: [],
    });
  };

  const handlePrescriptionChange = (e) => {
    const { name, value } = e.target;
    setPrescriptionForm(prev => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleMedicationChange = (index, field, value) => {
    const newMedications = [...prescriptionForm.medications];
    newMedications[index] = {
      ...newMedications[index],
      [field]: value,
    };
    setPrescriptionForm(prev => ({
      ...prev,
      medications: newMedications,
    }));
  };

  const addMedication = () => {
    setPrescriptionForm(prev => ({
      ...prev,
      medications: [
        ...prev.medications,
        { name: '', dosage: '', frequency: '', duration: '' },
      ],
    }));
  };

  const removeMedication = (index) => {
    setPrescriptionForm(prev => ({
      ...prev,
      medications: prev.medications.filter((_, i) => i !== index),
    }));
  };

  const handlePrescriptionSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post(
        'http://localhost:5000/api/prescriptions',
        {
          ...prescriptionForm,
          appointmentId: selectedAppointment._id,
          patientId: selectedAppointment.patientId._id,
        },
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );
      setSuccess('Prescription created successfully');
      handleClosePrescriptionDialog();
      fetchDashboardData();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to create prescription');
    }
  };

  const handleCompleteAppointment = async (appointmentId) => {
    try {
      await axios.put(
        `http://localhost:5000/api/appointments/${appointmentId}/complete`,
        {},
        { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
      );
      setSuccess('Appointment completed successfully');
      fetchDashboardData();
    } catch (err) {
      setError('Failed to complete appointment');
    }
  };

  const handleAddPrescription = async () => {
    try {
      await axios.post(`http://localhost:5000/api/appointments/${selectedAppointment._id}/prescription`, {
        prescription: prescriptionNote,
      });
      setOpenDialog(false);
      setPrescriptionNote('');
      fetchAppointments();
    } catch (error) {
      console.error('Error adding prescription:', error);
    }
  };

  const handleCancelAppointment = async (appointmentId) => {
    try {
      await axios.put(`http://localhost:5000/api/appointments/${appointmentId}/cancel`);
      fetchAppointments();
      fetchDashboardData();
    } catch (error) {
      console.error('Error canceling appointment:', error);
    }
  };

  const StatCard = ({ title, value, icon, color }) => (
    <Card>
      <CardContent>
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
          <Box
            sx={{
              backgroundColor: `${color}15`,
              borderRadius: 1,
              p: 1,
              mr: 2,
            }}
          >
            {icon}
          </Box>
          <Typography variant="h6" color="text.secondary">
            {title}
          </Typography>
        </Box>
        <Typography variant="h4" component="div">
          {value}
        </Typography>
      </CardContent>
    </Card>
  );

  return (
    <Container maxWidth="lg">
      <Box sx={{ mt: 4, mb: 4 }}>
        <Typography variant="h4" gutterBottom>
          Doctor Dashboard
        </Typography>
        <Typography variant="body1" color="text.secondary">
          Welcome back, Dr. {user?.name}
        </Typography>
      </Box>

      {error && (
        <Alert severity="error" sx={{ mb: 2 }}>
          {error}
        </Alert>
      )}

      {success && (
        <Alert severity="success" sx={{ mb: 2 }}>
          {success}
        </Alert>
      )}

      {/* Statistics Cards */}
      <Grid container spacing={3} sx={{ mb: 4 }}>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            title="Today's Appointments"
            value={stats.todayAppointments}
            icon={<EventIcon sx={{ color: 'primary.main' }} />}
            color="primary"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            title="Total Patients"
            value={stats.totalPatients}
            icon={<PeopleIcon sx={{ color: 'success.main' }} />}
            color="success"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            title="Total Appointments"
            value={stats.totalAppointments}
            icon={<HospitalIcon sx={{ color: 'warning.main' }} />}
            color="warning"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            title="Completed"
            value={stats.completedAppointments}
            icon={<CheckCircleIcon sx={{ color: 'info.main' }} />}
            color="info"
          />
        </Grid>
      </Grid>

      {/* Today's Appointments */}
      <Paper sx={{ p: 3, mb: 4 }}>
        <Typography variant="h6" gutterBottom>
          Today's Appointments
        </Typography>
        <TableContainer>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Time</TableCell>
                <TableCell>Patient</TableCell>
                <TableCell>Type</TableCell>
                <TableCell>Status</TableCell>
                <TableCell>Actions</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {todayAppointments.map((appointment) => (
                <TableRow key={appointment._id}>
                  <TableCell>
                    {new Date(appointment.time).toLocaleTimeString()}
                  </TableCell>
                  <TableCell>{appointment.patientId.userId.name}</TableCell>
                  <TableCell>{appointment.type}</TableCell>
                  <TableCell>
                    <Chip
                      label={appointment.status}
                      color={
                        appointment.status === 'scheduled'
                          ? 'primary'
                          : appointment.status === 'completed'
                          ? 'success'
                          : 'error'
                      }
                      size="small"
                    />
                  </TableCell>
                  <TableCell>
                    {appointment.status === 'scheduled' && (
                      <>
                        <Button
                          size="small"
                          color="primary"
                          onClick={() => handleOpenPrescriptionDialog(appointment)}
                          sx={{ mr: 1 }}
                        >
                          Write Prescription
                        </Button>
                        <Button
                          size="small"
                          color="success"
                          onClick={() => handleCompleteAppointment(appointment._id)}
                        >
                          Complete
                        </Button>
                      </>
                    )}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      </Paper>

      {/* Recent Patients */}
      <Paper sx={{ p: 3 }}>
        <Typography variant="h6" gutterBottom>
          Recent Patients
        </Typography>
        <List>
          {recentPatients.map((patient) => (
            <React.Fragment key={patient._id}>
              <ListItem>
                <ListItemIcon>
                  <PeopleIcon />
                </ListItemIcon>
                <ListItemText
                  primary={patient.userId.name}
                  secondary={`Last Visit: ${new Date(patient.lastVisit).toLocaleDateString()}`}
                />
                <Button
                  size="small"
                  onClick={() => navigate(`/doctor/patients/${patient._id}`)}
                >
                  View History
                </Button>
              </ListItem>
              <Divider />
            </React.Fragment>
          ))}
        </List>
      </Paper>

      {/* Prescription Dialog */}
      <Dialog
        open={openPrescriptionDialog}
        onClose={handleClosePrescriptionDialog}
        maxWidth="md"
        fullWidth
      >
        <DialogTitle>
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <Typography variant="h6">Write Prescription</Typography>
            <IconButton onClick={handleClosePrescriptionDialog}>
              <CloseIcon />
            </IconButton>
          </Box>
        </DialogTitle>
        <DialogContent>
          <Box component="form" onSubmit={handlePrescriptionSubmit} sx={{ mt: 2 }}>
            <Grid container spacing={3}>
              <Grid item xs={12}>
                <TextField
                  required
                  fullWidth
                  multiline
                  rows={3}
                  label="Diagnosis"
                  name="diagnosis"
                  value={prescriptionForm.diagnosis}
                  onChange={handlePrescriptionChange}
                />
              </Grid>
              <Grid item xs={12}>
                <Typography variant="h6" gutterBottom>
                  Medications
                </Typography>
                {prescriptionForm.medications.map((medication, index) => (
                  <Grid container spacing={2} key={index} sx={{ mb: 2 }}>
                    <Grid item xs={12} sm={3}>
                      <TextField
                        fullWidth
                        label="Medicine Name"
                        value={medication.name}
                        onChange={(e) => handleMedicationChange(index, 'name', e.target.value)}
                      />
                    </Grid>
                    <Grid item xs={12} sm={3}>
                      <TextField
                        fullWidth
                        label="Dosage"
                        value={medication.dosage}
                        onChange={(e) => handleMedicationChange(index, 'dosage', e.target.value)}
                      />
                    </Grid>
                    <Grid item xs={12} sm={3}>
                      <TextField
                        fullWidth
                        label="Frequency"
                        value={medication.frequency}
                        onChange={(e) => handleMedicationChange(index, 'frequency', e.target.value)}
                      />
                    </Grid>
                    <Grid item xs={12} sm={2}>
                      <TextField
                        fullWidth
                        label="Duration"
                        value={medication.duration}
                        onChange={(e) => handleMedicationChange(index, 'duration', e.target.value)}
                      />
                    </Grid>
                    <Grid item xs={12} sm={1}>
                      <IconButton
                        color="error"
                        onClick={() => removeMedication(index)}
                        disabled={prescriptionForm.medications.length === 1}
                      >
                        <CancelIcon />
                      </IconButton>
                    </Grid>
                  </Grid>
                ))}
                <Button
                  startIcon={<AddIcon />}
                  onClick={addMedication}
                  sx={{ mb: 2 }}
                >
                  Add Medication
                </Button>
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  multiline
                  rows={3}
                  label="Instructions"
                  name="instructions"
                  value={prescriptionForm.instructions}
                  onChange={handlePrescriptionChange}
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  multiline
                  rows={3}
                  label="Side Effects (one per line)"
                  name="sideEffects"
                  value={prescriptionForm.sideEffects.join('\n')}
                  onChange={(e) => {
                    setPrescriptionForm(prev => ({
                      ...prev,
                      sideEffects: e.target.value.split('\n').filter(effect => effect.trim()),
                    }));
                  }}
                />
              </Grid>
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleClosePrescriptionDialog}>Cancel</Button>
          <Button
            variant="contained"
            onClick={handlePrescriptionSubmit}
          >
            Save Prescription
          </Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default Dashboard;
